# -------------------- check_idempotency_lock --------------------


class TestIdempotencyLock:
    """幂等性锁验证。"""

    @pytest.mark.asyncio
    async def test_lock_acquired_returns_true(self) -> None:
        """Redis SET NX 成功（锁获取成功）应返回 True。"""
        from backend.ai_router import check_idempotency_lock

        redis = AsyncMock()
        redis.set = AsyncMock(return_value=True)

        request = MagicMock()
        request.app.state.redis = redis

        result = await check_idempotency_lock(request, "key-001")
        assert result is True
        redis.set.assert_awaited_once()

    @pytest.mark.asyncio
    async def test_lock_already_held_returns_false(self) -> None:
        """Redis SET NX 返回 False（锁已被持有）应返回 False。"""
        from backend.ai_router import check_idempotency_lock

        redis = AsyncMock()
        redis.set = AsyncMock(return_value=False)

        request = MagicMock()
        request.app.state.redis = redis

        result = await check_idempotency_lock(request, "key-002")
        assert result is False

    @pytest.mark.asyncio
    async def test_redis_none_returns_true_degraded(self) -> None:
        """Redis 不可用时应降级放行（返回 True）。"""
        from backend.ai_router import check_idempotency_lock

        request = MagicMock()
        request.app.state.redis = None

        result = await check_idempotency_lock(request, "key-003")
        assert result is True

    @pytest.mark.asyncio
    async def test_redis_error_returns_true_degraded(self) -> None:
        """Redis 操作抛异常时应降级放行。"""
        from backend.ai_router import check_idempotency_lock

        redis = AsyncMock()
        redis.set = AsyncMock(side_effect=ConnectionError("redis down"))

        request = MagicMock()
        request.app.state.redis = redis

        result = await check_idempotency_lock(request, "key-004")
        assert result is True

    @pytest.mark.asyncio
    async def test_lock_key_format(self) -> None:
        """锁 key 应包含 zen70:ai:idemp: 前缀。"""
        from backend.ai_router import check_idempotency_lock

        redis = AsyncMock()
        redis.set = AsyncMock(return_value=True)

        request = MagicMock()
        request.app.state.redis = redis

        await check_idempotency_lock(request, "my-unique-key")

        # 安全提取 key：优先 kwargs["name"]，其次 args[0]，无则断言失败
        call_args = redis.set.call_args
        if call_args.kwargs and "name" in call_args.kwargs:
            actual_key = call_args.kwargs["name"]
        elif call_args.args:
            actual_key = call_args.args[0]
        else:
            raise AssertionError(f"redis.set 未传入 key 参数: {call_args}")
        assert actual_key == "zen70:ai:idemp:my-unique-key"


