# -------------------- 配置安全性 --------------------


class TestAIRouterConfig:
    """AI 路由配置安全性。"""

    def test_http_client_has_connection_limits(self) -> None:
        """全局 HTTP 客户端必须配置连接池上限。"""
        from backend.ai_router import http_client

        # httpx 内部结构不稳定，安全提取连接池限制
        transport = getattr(http_client, "_transport", None)
        assert transport is not None, "http_client 缺少 _transport"
        pool = getattr(transport, "_pool", None)
        if pool is not None:
            max_conn = getattr(pool, "_max_connections", None)
            if max_conn is not None:
                assert max_conn <= 200, f"连接池上限 {max_conn} 超过 200"

    def test_router_prefix(self) -> None:
        """路由前缀应为 /api/v1/ai。"""
        from backend.ai_router import router

        assert router.prefix == "/api/v1/ai"
